import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"广济寺","description":"","frontmatter":{},"headers":[],"relativePath":"religion/guangji.md","filePath":"religion/guangji.md","lastUpdated":null}'),i={name:"religion/guangji.md"};function n(o,t,d,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="广济寺" tabindex="-1">广济寺 <a class="header-anchor" href="#广济寺" aria-label="Permalink to &quot;广济寺&quot;">​</a></h1><blockquote><p>&quot;中国佛教协会所在地，免费斋饭闻名。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>广济寺位于北京市西城区，是中国佛教协会所在地，也是北京市区重要的佛教活动场所。广济寺始建于金代，距今已有800余年历史。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">7:00-16:30</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">30分钟-1小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线西四站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区阜成门内大街25号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>广济寺始建于金代，原名西刘村寺，是佛教寺院。</p><h3 id="明代重建" tabindex="-1">明代重建 <a class="header-anchor" href="#明代重建" aria-label="Permalink to &quot;明代重建&quot;">​</a></h3><p>明天顺年间（1457-1464年），在原址重建，改名&quot;弘慈广济寺&quot;。</p><h3 id="清代发展" tabindex="-1">清代发展 <a class="header-anchor" href="#清代发展" aria-label="Permalink to &quot;清代发展&quot;">​</a></h3><p>清代，广济寺香火鼎盛，是京城重要的佛教寺院。</p><h3 id="现代" tabindex="-1">现代 <a class="header-anchor" href="#现代" aria-label="Permalink to &quot;现代&quot;">​</a></h3><p>1953年，中国佛教协会成立，会址设在广济寺。广济寺成为全国性佛教组织的所在地。</p><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>山门是广济寺的入口。</p><h3 id="天王殿" tabindex="-1">天王殿 <a class="header-anchor" href="#天王殿" aria-label="Permalink to &quot;天王殿&quot;">​</a></h3><p>天王殿供奉弥勒佛和四大天王。</p><h3 id="大雄宝殿" tabindex="-1">大雄宝殿 <a class="header-anchor" href="#大雄宝殿" aria-label="Permalink to &quot;大雄宝殿&quot;">​</a></h3><p>大雄宝殿是广济寺的主殿，供奉释迦牟尼佛。</p><h4 id="三世佛" tabindex="-1">三世佛 <a class="header-anchor" href="#三世佛" aria-label="Permalink to &quot;三世佛&quot;">​</a></h4><p>大雄宝殿供奉三世佛：</p><ul><li><strong>过去佛</strong>：燃灯佛</li><li><strong>现在佛</strong>：释迦牟尼佛</li><li><strong>未来佛</strong>：弥勒佛</li></ul><h3 id="圆通殿" tabindex="-1">圆通殿 <a class="header-anchor" href="#圆通殿" aria-label="Permalink to &quot;圆通殿&quot;">​</a></h3><p>圆通殿供奉观音菩萨。</p><h3 id="藏经楼" tabindex="-1">藏经楼 <a class="header-anchor" href="#藏经楼" aria-label="Permalink to &quot;藏经楼&quot;">​</a></h3><p>藏经楼收藏佛教经典，包括《大藏经》等珍贵典籍。</p><h2 id="中国佛教协会" tabindex="-1">中国佛教协会 <a class="header-anchor" href="#中国佛教协会" aria-label="Permalink to &quot;中国佛教协会&quot;">​</a></h2><p>广济寺是中国佛教协会所在地，是全国性佛教组织的总部。</p><h3 id="主要职能" tabindex="-1">主要职能 <a class="header-anchor" href="#主要职能" aria-label="Permalink to &quot;主要职能&quot;">​</a></h3><ul><li><strong>教务管理</strong>：管理全国佛教事务</li><li><strong>人才培养</strong>：培养佛教人才</li><li><strong>对外交流</strong>：开展国际佛教交流</li><li><strong>社会公益</strong>：开展慈善事业</li></ul><h3 id="重要活动" tabindex="-1">重要活动 <a class="header-anchor" href="#重要活动" aria-label="Permalink to &quot;重要活动&quot;">​</a></h3><ul><li><strong>佛诞节</strong>：每年农历四月初八，庆祝佛诞</li><li><strong>观音诞</strong>：每年农历二月十九，庆祝观音诞</li><li><strong>水陆法会</strong>：大型佛教法会</li></ul><h2 id="免费斋饭" tabindex="-1">免费斋饭 <a class="header-anchor" href="#免费斋饭" aria-label="Permalink to &quot;免费斋饭&quot;">​</a></h2><p>广济寺以免费斋饭闻名，每天中午为信众提供斋饭。</p><h3 id="斋饭时间" tabindex="-1">斋饭时间 <a class="header-anchor" href="#斋饭时间" aria-label="Permalink to &quot;斋饭时间&quot;">​</a></h3><p>每天11:00-12:00。</p><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li><strong>免费</strong>：不收取费用</li><li><strong>排队</strong>：需要排队领取</li><li><strong>珍惜粮食</strong>：按需领取，珍惜粮食</li><li><strong>保持安静</strong>：保持安静</li></ul><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>寺庙参观（约30分钟-1小时）</strong>：</p><p>山门 → 天王殿 → 大雄宝殿 → 圆通殿 → 藏经楼 → 出寺</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">4号线西四站A口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">13路、22路、38路等西四路口北站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从西单步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>免费参观</strong>：免费开放</li><li><strong>免费斋饭</strong>：中午有免费斋饭</li><li><strong>保持安静</strong>：佛协所在地，保持安静</li><li><strong>尊重礼仪</strong>：尊重佛教礼仪</li><li><strong>结合游览</strong>：可与白塔寺、历代帝王庙一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">白塔寺</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">藏传佛教寺院</td></tr><tr><td style="text-align:left;">历代帝王庙</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">祭祀历代帝王</td></tr><tr><td style="text-align:left;">西四</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老商业区</td></tr><tr><td style="text-align:left;">西单</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">商业区</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>广济寺是中国佛教协会所在地，是全国性佛教组织的总部。</p><p>广济寺是北京重要的佛教活动场所，香火旺盛。</p><p>广济寺的免费斋饭体现了佛教的慈悲精神。</p><hr><p><strong>📍 地址</strong>：北京市西城区阜成门内大街25号 <strong>📞 电话</strong>：010-66160895</p>',57)])])}const b=a(i,[["render",n]]);export{c as __pageData,b as default};
